import {
  Controller,
  Get,
  Post,
  Param,
  Body,
  Query,
  UseGuards,
  ParseUUIDPipe,
  Res,
} from '@nestjs/common';
import { Response } from 'express';
import { ReportsService } from './reports.service';
import { GenerateReportDto } from './dto/generate-report.dto';
import { ReportFilterDto } from './dto/report-filter.dto';
import { JwtAuthGuard } from '../../common/guards/jwt-auth.guard';
import { CurrentActor } from '../../common/decorators/current-actor.decorator';
import { JwtPayload } from '../../common/interfaces/jwt-payload.interface';

@Controller('reports')
@UseGuards(JwtAuthGuard)
export class ReportsController {
  constructor(private readonly reportsService: ReportsService) {}

  /**
   * GET /reports
   * Get all generated reports for the logged-in client
   */
  @Get()
  findMany(@Query() filter: ReportFilterDto, @CurrentActor() actor: JwtPayload) {
    if (!actor.clientId) {
      return { data: [], pagination: { page: 1, limit: 20, total: 0, totalPages: 0 } };
    }
    return this.reportsService.findMany(actor.clientId, filter);
  }

  /**
   * POST /reports/generate
   * Generate a new report
   */
  @Post('generate')
  generate(@Body() dto: GenerateReportDto, @CurrentActor() actor: JwtPayload) {
    if (!actor.clientId || !actor.actorId) {
      throw new Error('Client ID or Actor ID not found in token');
    }
    return this.reportsService.generate(actor.clientId, actor.actorId, dto);
  }

  /**
   * GET /reports/:id
   * Get a specific report by ID
   */
  @Get(':id')
  findOne(@Param('id', ParseUUIDPipe) id: string, @CurrentActor() actor: JwtPayload) {
    if (!actor.clientId) {
      throw new Error('Client ID not found in token');
    }
    return this.reportsService.findOne(id, actor.clientId);
  }

  /**
   * GET /reports/:id/download
   * Download a report (returns placeholder for now)
   */
  @Get(':id/download')
  async download(
    @Param('id', ParseUUIDPipe) id: string,
    @Query('format') format: string = 'pdf',
    @CurrentActor() actor: JwtPayload,
    @Res() res: Response,
  ) {
    if (!actor.clientId) {
      throw new Error('Client ID not found in token');
    }

    const report = await this.reportsService.findOne(id, actor.clientId);

    // For now, return a placeholder response
    // In production, this would generate and return the actual file
    const contentType = format === 'csv' ? 'text/csv' : 'application/pdf';
    const extension = format === 'csv' ? 'csv' : 'pdf';
    const filename = `${report.reportName}.${extension}`;

    res.setHeader('Content-Type', contentType);
    res.setHeader('Content-Disposition', `attachment; filename="${filename}"`);

    // Return placeholder content
    const placeholder = format === 'csv' 
      ? 'Report data would be here in CSV format'
      : 'Report data would be here in PDF format';

    res.send(placeholder);
  }
}


